text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시점은 스모크 테스트가 통과하는 경우에 한해 금요일 15:00 KST로 정했다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토하기로 했다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경하자는 제안은 거절되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스는 내부 스트레치 목표로만 언급되었고, 공개 릴리스 결정으로 채택되지는 않았다."
      },
      {
        "goal": "README 설치 단계는 가능하면 목요일까지 검토하는 것이 바람직하다고 언급되었지만, 확정 일정이나 담당자는 정해지지 않았다."
      }
    ],
    "non_decisions": [
      {
        "item": "수요일 목표를 릴리스 노트에 포함할지 여부는 결정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래된 상태이면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "unspecified",
      "status": "confirmed but no exact deadline",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Unassigned",
      "task": "README 설치 단계를 목요일까지 검토할지 검토한다.",
      "due": "Thursday if possible",
      "status": "unassigned",
      "source_certainty": "confirmed as suggestion only"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "스모크 테스트 결과가 금요일 10:00 KST 이전에 확보되는지 확인한다.",
      "tarball 경로가 올바른지 확인한다.",
      "README 설치 단계가 최신인지 검토한다.",
      "최종 릴리스 승인 권한 보유자를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 결정한다."
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너명을 지어내지 않는다.",
      "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항을 추가하지 않는다.",
      "명시되지 않은 소유자, 마감일, 승인자, 고객 정보를 추정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "고객명은 명시되지 않았으므로 생성하지 않는다.",
    "예산 정보는 없으므로 생성하지 않는다.",
    "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "소유자와 마감일은 확인된 항목만 기록한다.",
    "수요일은 내부 스트레치 목표이며 확정 릴리스 일정으로 승격하지 않는다."
  ]
}
